async def request_permission(self, options, session_id, tool_call, **kwargs):
    """Handle permission requests from the agent.

    When auto_approve is True, selects the first non-cancelled option
    (matching --dangerously-skip-permissions behavior). When False,
    always cancels — the frontend would need to implement a permission
    prompt to support interactive approval (future work).
    """
    if self._auto_approve:
        for opt in options:
            if opt.get("kind") != "cancelled":
                return {"outcome": opt}
        # All options are cancel — return the first one
        return {"outcome": options[0]}
    else:
        # Find the cancel/deny option
        for opt in options:
            if opt.get("kind") == "cancelled":
                return {"outcome": opt}
        return {"outcome": options[0]}

