class TestClient(acp.Client):
    async def session_update(self, session_id, update, **kwargs):
        su = update.get("sessionUpdate", "") if isinstance(update, dict) else getattr(update, "sessionUpdate", "")
        if su == "agent_message_chunk":
            content = update.get("content", {}) if isinstance(update, dict) else getattr(update, "content", {})
            text = content.get("text", "") if isinstance(content, dict) else getattr(content, "text", "")
            if text:
                print(f"  TEXT: {text}", end="", flush=True)
        elif su in ("tool_call", "tool_call_update"):
            pass
        elif su == "user_message_chunk":
            content = update.get("content", {}) if isinstance(update, dict) else getattr(update, "content", {})
            text = content.get("text", "") if isinstance(content, dict) else getattr(content, "text", "")
            print(f"  USER_REPLAY: {text[:80]}...")
        else:
            print(f"  {su}")

    async def request_permission(self, options, session_id, tool_call, **kwargs):
        # Dump the full structure of the first option
        if options:
            opt = options[0]
            print(f"\n  PERMISSION OPTIONS ({len(options)} total):")
            for i, o in enumerate(options):
                if isinstance(o, dict):
                    print(f"    [{i}]: {json.dumps(o, default=str)[:200]}")
                else:
                    print(f"    [{i}]: optionId={getattr(o, 'optionId', '?')} kind={getattr(o, 'kind', '?')}")
            oid = opt.get("optionId", None) if isinstance(opt, dict) else getattr(opt, "optionId", None)
            return {"outcome": "selected", "optionId": oid}
        return {"outcome": "cancelled"}

    async def read_text_file(self, path, **kwargs):
        try:
            with open(path) as f:
                return {"content": f.read()}
        except:
            return {"content": ""}

    async def write_text_file(self, path, content, **kwargs):
        with open(path, "w") as f:
            f.write(content)

async def main():
    async with acp.spawn_agent_process(
        TestClient(),
        "npx", "@agentclientprotocol/claude-agent-acp"
    ) as (conn, proc):
        result = await conn.initialize(
            protocol_version=acp.PROTOCOL_VERSION,
            client_capabilities=ClientCapabilities(
                fs={"readTextFile": True, "writeTextFile": True}
            ),
            client_info=Implementation(name="test-spike", title="Test Spike", version="0.1.0"),
        )

        # Test prompt that triggers a permission request (file write)
        print("Creating session in agent-kitchen repo...")
        session = await conn.new_session(
            cwd="/Users/haldar/repos/gh/agent-kitchen",
            mcp_servers=[]
        )
        sid = session.sessionId
        print(f"Session: {sid}")

        print("\nPrompt: write a temp file (should trigger permission)...")
        response = await conn.prompt(
            session_id=sid,
            prompt=[acp.text_block("Create file /tmp/acp_test_output.txt containing 'hello from acp'. Use the Write tool.")],
        )
        print(f"\nStop reason: {response.stopReason}")

        # Check the file was created
        import os
        if os.path.exists("/tmp/acp_test_output.txt"):
            print(f"File created: {open('/tmp/acp_test_output.txt').read()}")
        else:
            print("File NOT created")

asyncio.run(main())
